    _frames.addAll(bytes);

    while (_frames.length >= 2) {
      final first = _frames[0];
      final second = _frames[1];
      if ((second & 0x80) != 0) {
        throw const FormatException('server frames must not be masked');
      }
      final length = second & 0x7f;
      if (length >= 126) {
        throw const FormatException('extended payloads are not supported');
      }
      if (_frames.length < 2 + length) {
        break;
      }

      _frames.removeRange(0, 2 + length);
      yield WebSocketFrame(
        finalFragment: (first & 0x80) != 0,
        opcode: first & 0x0f,
        payload: _frames.sublist(0, length),
      );
    }
  }
}
